return [
  { json: { url: "https://feeds.bloomberg.com/markets/news.rss", source: "Bloomberg" } },
  { json: { url: "https://feeds.reuters.com/reuters/businessNews", source: "Reuters" } },
  { json: { url: "https://finance.yahoo.com/news/rssindex", source: "Yahoo Finance" } }
]

const items = $input.all();
const articles = [];

for (const item of items) {
  const source = item.json.source || "Unknown";

  // navigate the already-parsed JSON structure
  const channel = item.json.rss?.channel;
  if (!channel) continue;

  const feedItems = channel.item || [];
  const list = Array.isArray(feedItems) ? feedItems : [feedItems];

  for (const a of list) {
    const title = a.title?._ || a.title || "";
    const desc  = a.description?._ || a.description || "";
    const link  = a.link || "";
    const date  = a.pubDate || "";

    // extract tickers
    let ticker = "";
    if (a.category) {
      const cats = Array.isArray(a.category) ? a.category : [a.category];
      ticker = cats.map(c => c._ || c).join(", ");
    }

    if (!title) continue;

    articles.push({
      json: {
        source,
        title:       title.trim(),
        description: desc.trim().slice(0, 300),
        link:        link.trim(),
        pubDate:     date.trim(),
        ticker,
      }
    });
  }
}

if (articles.length === 0) {
  return [{ json: { error: "no articles found", sample: JSON.stringify($input.all()[0].json).slice(0, 500) } }];
}

return articles;

const articles = $input.all().slice(0, 15);

let articleText = "";
articles.forEach((a, i) => {
  articleText += `${i + 1}. [${a.json.source}] ${a.json.title}\n   ${a.json.description}\n\n`;
});

const today = new Date().toLocaleDateString("en-US", {
  weekday: "long", year: "numeric", month: "long", day: "numeric"
});

const prompt = `You are a sharp financial analyst. Analyze today's top financial news.

TODAY'S ARTICLES:
${articleText}

Return ONLY valid JSON, no markdown, no extra text:
{
  "date": "${today}",
  "overall_sentiment": "Bullish or Bearish or Neutral",
  "sentiment_reason": "one sentence explaining why",
  "top_themes": [
    {"theme": "theme name", "summary": "2 sentence explanation", "articles": ["title1", "title2"]},
    {"theme": "theme name", "summary": "2 sentence explanation", "articles": ["title1"]},
    {"theme": "theme name", "summary": "2 sentence explanation", "articles": ["title1"]}
  ],
  "key_tickers": ["TICKER1", "TICKER2", "TICKER3", "TICKER4", "TICKER5"],
  "market_summary": "3-4 sentence paragraph of what investors need to know today",
  "watch_today": ["item 1", "item 2", "item 3"],
  "contrarian_take": "one provocative contrarian perspective on today's news"
}`;

return [{ json: { prompt, articleCount: articles.length, date: today } }];

